def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_factor = np.tanh(ratio * 3) + 1.5
        complexity = 0.0
        decay = 1.0
        growth = 1.0
        modifier = 1.0
        special_penalty = 0.0
        for x in range(1, 15):
            fb = np.cos(x * ratio * 2) + np.sin(cap / (x + 1))
            if fb < 0:
                decay *= (1 + 0.01 * x)
            else:
                growth *= (1 - 0.005 * x)
            if x % 4 == 0 and cap % (x + 2) == 0:
                modifier *= 1.03
            elif x % 5 == 0 and (cap + x) % 3 == 0:
                modifier *= 0.97
            if ratio < (x * 0.08):
                complexity += (np.exp(-ratio * x) + np.log1p(x)) * fb * growth
            else:
                complexity += (x**1.5 + ratio*x) / (x + 1) * decay
            if x == 7:
                for y in range(1, 7):
                    diff = cap - item * y**3
                    if diff > 0 and diff % (y + 3) == 0:
                        special_penalty += np.log1p(diff) / (y + 1)
                    else:
                        special_penalty -= (abs(diff) ** 1.1) / (y + 4)
            if ratio > 0.7 and x % 3 == 0:
                modifier *= (1 + 0.015 * x)
            elif ratio < 0.15 and x % 2 == 1:
                modifier *= (0.95 - 0.008 * x)
            if (cap * x) % 11 == 0:
                complexity *= 1.05
            if (cap + x*x) % 9 == 0:
                complexity *= 0.93
        complexity += special_penalty * 0.7
        complexity *= modifier * base_factor
        if complexity == 0:
            priorities[i] = np.inf
            continue
        if cap > item * 3.5:
            priorities[i] = -complexity / (np.log1p(cap) + 1) * (1 + ratio**2)
        else:
            priorities[i] = -complexity / (cap**0.7 + 2) * np.exp(-ratio)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.78
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.1
        if i % 2 == 0:
            priorities[i] *= (1 + 0.02 * (i % 5))
        else:
            priorities[i] *= (1 - 0.015 * (i % 4))
    return priorities
